class TokenBudget:
    def __init__(self, limit: int):
        self.limit = limit
        self.spent = 0

    def charge(self, tokens: int) -> bool:
        """Deduct tokens; return True if budget remains."""""
        if self.spent + tokens > self.limit:
            return False
        self.spent += tokens
        return True

    @property
    def remaining(self) -> int:
        return self.limit - self.spent

    def __repr__(self) -> str:
        return f"TokenBudget(spent={self.spent}/{self.limit})"

budget = TokenBudget(limit=10_000)
ok = budget.charge(3_000)
print(ok, budget)            # True  TokenBudget(spent=3000/10000)
print(budget.remaining)      # 7000

class SearchTool:
    """Callable tool wrapping a retriever — implement __call__ so the agent
    dispatcher can invoke any tool uniformly: result = tool(query)."""""

    def __init__(self, retriever, top_k: int = 5, name: str = "search"):
        self.retriever = retriever
        self.top_k = top_k
        self.name = name

    def __call__(self, query: str) -> list[str]:
        return self.retriever.search(query, limit=self.top_k)

    def __repr__(self) -> str:
        return f"SearchTool(name={self.name!r}, top_k={self.top_k})"

# The agent loop can treat any tool uniformly:
tools: list = [SearchTool(retriever), CalculatorTool(), WeatherTool()]
