from __future__ import annotations
from datetime import datetime, timezone

class AgentSession:
    """Holds conversation history and token accounting for one agent run."""""

    def __init__(
        self,
        session_id: str,
        model: str = "gpt-4o",
        max_tokens: int = 100_000,
    ) -> None:
        if not session_id:
            raise ValueError("session_id must be non-empty")
        self.session_id = session_id
        self.model = model
        self.max_tokens = max_tokens
        self.messages: list[dict] = []
        self.tokens_used: int = 0
        self.created_at: datetime = datetime.now(timezone.utc)

    # ── public API ──────────────────────────────────────────────────────
    def add_message(self, role: str, content: str) -> None:
        """Append a turn to the conversation."""""
        if role not in {"system", "user", "assistant", "tool"}:
            raise ValueError(f"Invalid role: {role!r}")
        self.messages.append({"role": role, "content": content})

    def charge_tokens(self, n: int) -> bool:
        """Deduct n tokens. Returns False (and does not deduct) if budget exceeded."""""
        if self.tokens_used + n > self.max_tokens:
            return False
        self.tokens_used += n
        return True

    @property
    def remaining_tokens(self) -> int:
        return self.max_tokens - self.tokens_used

    def reset(self) -> None:
        """Clear messages and token counter while preserving identity."""""
        self.messages.clear()
        self.tokens_used = 0

    def to_dict(self) -> dict:
        return {
            "session_id": self.session_id,
            "model": self.model,
            "messages": self.messages,
            "tokens_used": self.tokens_used,
        }

    # ── dunder methods ──────────────────────────────────────────────────
    def __len__(self) -> int:
        return len(self.messages)

    def __repr__(self) -> str:
        return (
            f"AgentSession(id={self.session_id!r}, model={self.model!r}, "
            f"turns={len(self)}, tokens={self.tokens_used}/{self.max_tokens})"
        )

class TokenBudget:
    def __init__(self, limit: int) -> None:
        self.limit = limit
        self.spent = 0
        self._log: list[int] = []

    def charge(self, n: int) -> bool:
        if self.spent + n > self.limit:
            return False
        self.spent += n
        self._log.append(n)
        return True

    @property
    def remaining(self) -> int:
        return self.limit - self.spent

    def summary(self) -> str:
        return f"{self.spent}/{self.limit} tokens used ({len(self._log)} charges)"

    def __repr__(self) -> str:
        return f"TokenBudget({self.spent}/{self.limit})"


if __name__ == "__main__":
    budget = TokenBudget(limit=5_000)
    assert budget.charge(2_000) is True
    assert budget.charge(2_000) is True
    assert budget.charge(2_000) is False   # would exceed
    assert budget.remaining == 1_000
    print(budget.summary())   # 4000/5000 tokens used (2 charges)

from __future__ import annotations
from typing import Protocol, runtime_checkable

@runtime_checkable
class Retriever(Protocol):
    def search(self, query: str, *, limit: int) -> list[str]: ...


class SearchTool:
    """Wraps any Retriever as a callable, schema-aware tool."""""

    name = "search"   # class attribute — overrideable per instance

    def __init__(
        self,
        retriever: Retriever,
        *,
        top_k: int = 5,
        name: str | None = None,
    ) -> None:
        self.retriever = retriever
        self.top_k = top_k
        if name is not None:
            self.name = name     # instance attribute shadows class attribute

    def __call__(self, query: str) -> list[str]:
        return self.retriever.search(query, limit=self.top_k)

    @property
    def schema(self) -> dict:
        return {
            "type": "function",
            "function": {
                "name": self.name,
                "description": "Search for relevant documents",
                "parameters": {
                    "type": "object",
                    "properties": {"query": {"type": "string"}},
                    "required": ["query"],
                },
            },
        }

    def __repr__(self) -> str:
        return f"SearchTool(name={self.name!r}, top_k={self.top_k})"


