from dataclasses import dataclass, field
from abc import ABC, abstractmethod
from typing import Protocol

# ── Protocol: structural interface without inheritance ──────────────────────
class LLMClient(Protocol):
    def complete(self, messages: list[dict], **kwargs) -> object: ...

# ── ABC: enforcement via inheritance ────────────────────────────────────────
class BaseTool(ABC):
    name: str = ""

    @abstractmethod
    def __call__(self, **kwargs) -> object:
        """Execute the tool and return a JSON-serialisable result."""""

    @property
    def schema(self) -> dict:
        return {"type": "function", "function": {"name": self.name}}

class WebSearch(BaseTool):
    name = "web_search"

    def __call__(self, query: str) -> list[str]:  # must implement
        return ["result-1", "result-2"]

# ── Pydantic BaseModel for validated, serialisable session state ─────────────
from pydantic import BaseModel, Field

class SessionState(BaseModel):
    session_id: str
    model: str = "gpt-4o"
    messages: list[dict] = Field(default_factory=list)
    tokens_used: int = 0

    def to_redis(self) -> str:
        return self.model_dump_json()

    @classmethod
    def from_redis(cls, raw: str) -> "SessionState":
        return cls.model_validate_json(raw)
